/* overlay manifest: obj3_build() copies each entry's storage into the image. */
typedef struct {
    const char *name;
    uint32_t    off;     /* byte offset into the obj3 image */
    uint32_t    size;    /* bytes owned */
    const void *ptr;     /* the owning C object's storage */
    const uint32_t *reloc_slots;  /* symbol-relative offsets of the 4-byte reloc
                                   * slots inside this region (0 if none) — the
                                   * reloc pass overwrites them, so the
                                   * owned-storage selfcheck masks them out */
    uint32_t    n_reloc_slots;
} obj3_owned_t;
extern const obj3_owned_t obj3_owned_tab[];
extern const unsigned obj3_owned_count;

/* Compare an owned symbol's C storage against the built image region, SKIPPING
 * its reloc-slot byte ranges (reloc-overwritten in the image, pre-reloc
 * placeholder in owned storage). Everything outside the slots is byte-compared.
 * Returns 0 on match, else (first-mismatch symbol-offset + 1). */
int obj3_owned_region_cmp(const obj3_owned_t *o, const unsigned char *image_base);

#endif /* ROTH_OBJ3_OWNED_H */
